#include <iostream> using namespace std; float gradeToPoint(char grade) { switch(grade) { case 'A': return 10; case 'B': return 8; case 'C': return 6; case 'D': return 4; case 'F': return 0; default: return 0; } } int main() { int n; cout << "Enter number of subjects: "; cin >> n; float total = 0; for(int i = 0; i < n; i++) { char grade; cout << "Enter grade (A/B/C/D/F): "; cin >> grade; total += gradeToPoint(grade); } cout << "CGPA = " << total / n; } 